import http from '../http'
//产品管理


//产品

// 合作伙伴
export function partenrList(query: any) {
    return http.get('/jkyErp/partenr/list', query)
}

// 产品详细
export function getpartenr(id: any) {
    return http.get('/jkyErp/partenr/' + id)
}
// 新增用户
export function addpartenr(data: any) {
    return http.post('/jkyErp/partenr/add', data)
}

// 修改用户
export function edipartenr(data: any) {
    return http.post('/jkyErp/partenr/edit', data)
}

// 删除用户
export function delpartenr(teamId: number) {
    return http.post('/jkyErp/partenr/del',teamId)
}







