<template>
  <a-card>
    <div :class="advanced ? 'search' : null">
      <a-form layout="horizontal">
        <div :class="advanced ? null : 'fold'">
          <a-row>
            <a-col :md="8" :sm="24">
              <a-form-item
                label="公司名称搜索: "
                :labelCol="{ span: 5 }"
                :wrapperCol="{ span: 18, offset: 1 }"
              >
                <a-input
                  placeholder="请输入公司名称: "
                  v-model:value="queryParams.partnername"
                />
              </a-form-item>
            </a-col>
          </a-row>
        </div>
        <span style="float: right; margin-top: 3px">
          <a-button type="primary" @click="handleSearch">查询</a-button>
          <a-button style="margin-left: 8px" @click="Reset">重置</a-button>
          <a @click="toggleAdvanced" style="margin-left: 8px">
            {{ advanced ? "收起" : "展开" }}
          </a>
        </span>
      </a-form>
    </div>
    <div>
      <a-space class="operator">
        <a-button @click="handleAdd" type="primary">新建</a-button>
        <a-button
          @click="handleUpdate"
          type="primary"
          :disabled="selectedRowKeys.length == 1 ? false : true"
          >编辑</a-button
        >
        <a-button
          @click="handleDel"
          type="primary"
          :disabled="selectedRowKeys.length > 0 ? false : true"
          danger
          >删除
        </a-button>
      </a-space>
      <a-table
        rowKey="id"
        :pagination="false"
        :columns="columns"
        :data-source="dataSource"
        :row-selection="{
          selectedRowKeys: selectedRowKeys,
          onChange: onSelectChange,
        }"
      >
      </a-table>
      <a-pagination
        v-show="total > 0"
        show-size-changer
        :show-total="(total) => `共 ${total} 条`"
        v-model:current="queryParams.current"
        v-model:pageSize="queryParams.size"
        :total="total"
        show-less-items
        @showSizeChange="onShowSizeChange"
        @change="onPageChange"
      />
    </div>
  </a-card>

  <a-modal
    :visible="open"
    :title="title"
    width="650px"
    @ok="handleOk"
    @cancel="handleCancel"
  >
    <a-form :model="form" :rules="rules" :validateOnRuleChange="true">
      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="公司名称" ref="partnername" name="partnername">
            <a-input
              placeholder="请输入公司名称"
              v-model:value="form.partnername"
            />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="公司地址: " ref="address" name="address">
            <a-input
              placeholder="请输入公司地址"
              v-model:value="form.address"
            />
          </a-form-item>
        </a-col>
      </a-row>

      <a-row :gutter="[16, 16]">
        <a-col :span="12">
          <a-form-item label="联系人:" ref="contact" name="contact">
            <a-input placeholder="请输入联系人" v-model:value="form.contact" />
          </a-form-item>
        </a-col>
        <a-col :span="12">
          <a-form-item label="联系方式: " ref="contactway" name="contactway">
            <a-input
              placeholder="请输入联系方式"
              v-model:value="form.contactway"
            />
          </a-form-item>
        </a-col>
      </a-row>
      <a-row :gutter="[16, 16]">
        <a-col :span="24">
          <a-form-item label="备注">
            <a-textarea
              rows="4"
              placeholder="请输入备注信息"
              v-model:value="form.remark"
              show-count
              :maxlength="100"
            />
          </a-form-item>
        </a-col>
      </a-row>
    </a-form>
  </a-modal>
</template>

<script>
const columns = [
  {
    title: "编号",
    dataIndex: "id",
  },
  {
    title: "公司名称",
    dataIndex: "partnername",
    scopedSlots: { customRender: "partnername" },
  },
  {
    title: "公司地址",
    dataIndex: "address",
    scopedSlots: { customRender: "address" },
  },
  {
    title: "联系人",
    dataIndex: "contact",
    scopedSlots: { customRender: "contact" },
  },
  {
    title: "联系方式",
    dataIndex: "contactway",
    scopedSlots: { customRender: "contactway" },
  },

  {
    title: "备注系方式",
    dataIndex: "remark",
    scopedSlots: { customRender: "remark" },
  },
];
const rules = {
  partnername: [{ required: true, message: "该为必填项", trigger: "blur" }],
  address: [{ required: true, message: "该为必填项", trigger: "blur" }],
  contact: [{ required: true, message: "该为必填项", trigger: "blur" }],
  contactway: [
    {
      pattern:
        /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
      message: "手机号不合法",
      trigger: "blur",
    },
    { required: true, message: "该为必填项", trigger: "blur" },
  ],
};
import {
  partenrList,
  addpartenr,
  getpartenr,
  delpartenr,
  edipartenr,
} from "@/server/http/api/partenrs";
import { message } from "ant-design-vue";
export default {
  name: "QueryList",
  components: {},
  data() {
    return {
      // 弹出层标题
      title: "",
      // 是否显示弹出层
      open: false,
      advanced: false,
      columns: columns,
      rules: rules,
      dataSource: [],
      selectedRows: [],
      selectedRowKeys: [],
      // 表单参数
      form: {},
      Pagination: {},
      total: 0,

      queryParams: {
        current: 1,
        size: 10,
        partnername: undefined,
      },
      // 选中数组
      ids: [],
      // 非单个禁用
      single: true,
      // 非多个禁用
      multiple: true,
      selteamList: [],
    };
  },
  authorize: {
    deleteRecord: "delete",
  },
  created() {
    this.getList();
  },

  methods: {
    onShowSizeChange(current, pageSize) {
      this.queryParams.current = current;
      this.queryParams.size = pageSize;
      this.getList();
    },
    onPageChange(pageNumber) {
      this.queryParams.current = pageNumber;
      this.getList();
    },
    //获取设备分类列表
    getList() {
      partenrList(this.queryParams).then((res) => {
        var data = res.data;
        this.dataSource = data.data.records;
        this.total = data.data.total;
      });
    },
    //查询数据
    handleSearch() {
      this.getList();
    },

    Reset() {
      this.queryParams = {
        current: 1,
        size: 10,
        partnername: undefined,
      };
      this.getList();
    },
    handleOk() {
      var myreg =
        /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/;
      if (
        !this.form.partnername ||
        !this.form.address ||
        !this.form.contact ||
        !myreg.test(this.form.contactway)
      ) {
        message.warning("缺少必填参数!");
         return;
      }
      this.submitForm();
    },
    handleCancel(e) {
      this.form = {};
      this.open = false;
    },
    deleteRecord(key) {
      this.dataSource = this.dataSource.filter((item) => item.key !== key);
      this.selectedRows = this.selectedRows.filter((item) => item.key !== key);
    },
    toggleAdvanced() {
      this.advanced = !this.advanced;
    },
    remove() {
      this.dataSource = this.dataSource.filter(
        (item) =>
          this.selectedRows.findIndex((row) => row.key === item.key) === -1
      );
      this.selectedRows = [];
    },
    onSelectChange(selection) {
      this.ids = selection.map((item) => item.id);
      this.single = selection.length !== 1;
      this.multiple = !selection.length;
      this.selectedRowKeys = selection;
    },
    /** 新增按钮操作 */
    handleAdd() {
      this.open = true;
      this.title = "添加合作伙伴";
    },
    /** 修改按钮操作 */
    handleUpdate(row) {
      this.loading = true;
      getpartenr(this.selectedRowKeys[0]).then((response) => {
        this.loading = false;
        this.form = response.data.data;
        this.open = true;
        this.title = "修改合作伙伴信息";
      });
    },
    /** 提交按钮 */
    submitForm() {
      this.buttonLoading = true;
      if (this.form.id != null) {
        edipartenr(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      } else {
        addpartenr(this.form)
          .then((response) => {
            this.open = false;
            this.form = {};
            this.getList();
          })
          .finally(() => {
            this.buttonLoading = false;
          });
      }
    },
    handleDel() {
      delpartenr(this.selectedRowKeys)
        .then((response) => {
          this.selectedRowKeys = [];
          this.getList();
        })
        .finally(() => {
          this.buttonLoading = false;
        });
    },
  },
};
</script>

<style lang="less" scoped>
.search {
  margin-bottom: 54px;
}
.fold {
  width: calc(100% - 216px);
  display: inline-block;
}
.operator {
  margin-bottom: 18px;
}
@media screen and (max-width: 900px) {
  .fold {
    width: 100%;
  }
}
</style>
